class Solution:
    def digitFrequencyScore(self, n: int) -> int:
        freq = {}
        for ch in str(n):
            freq[ch] = freq.get(ch, 0) + 1
        total = 0
        for ch, cnt in freq.items():
            total += int(ch) * cnt
        return total

solutions.python:
class Solution:
    def digitFrequencyScore(self, n: int) -> int:
        from collections import Counter
        c = Counter(str(n))
        return sum(int(d) * cnt for d, cnt in c.items())

