var digitFrequencyScore = function(n) {
    const s = String(n);
    const freq = {};
    for (const ch of s) freq[ch] = (freq[ch] || 0) + 1;
    let total = 0;
    for (const ch in freq) total += Number(ch) * freq[ch];
    return total;
};
